// Tomamos el item de entrada
const item = $input.first().json;

// Fecha actual
const now = $now;

// Lista de horas objetivo
const horas = [
  $('Edit Fields boom').first().json.hora9,
  $('Edit Fields boom').first().json.hora11,
  $('Edit Fields boom').first().json.hora13,
  $('Edit Fields boom').first().json.hora15,
  $('Edit Fields boom').first().json.hora19,
  $('Edit Fields boom').first().json.hora21,
  $('Edit Fields boom').first().json.hora23,
]
  .filter(Boolean)
  .map(h => new Date(h));

// Rango: ±10 minutos
const RANGO_MS = 10 * 60 * 1000;

// Verificar si now está dentro del rango de alguna hora
const isInRange = horas.some(hora => {
  const inicio = new Date(hora.getTime() - RANGO_MS);
  const fin = new Date(hora.getTime() + RANGO_MS);
  return now >= inicio && now <= fin;
});

// Devolver resultado
return [
  {
    json: {
      ...item,
      isInRange,
      now
    }
  }
];

