// ==========================
// 🔹 1. OBTENER RESPUESTA OPENAI
// ==========================
const input = $input.first().json;

let raw =
  input?.['0']?.content?.[0]?.text ||
  input?.content?.[0]?.text ||
  input?.message?.content ||
  input?.text ||
  "";

if (typeof raw !== "string") {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// ==========================
// 🔹 2. PARSEAR JSON
// ==========================
let parsed;
let jsonValido = true;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {};
  jsonValido = false;
}

// ==========================
// 🔹 3. FUNCIONES ÚTILES
// ==========================
const normalize = (str) => {
  if (str === null || str === undefined) return "";
  return String(str)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
};

const onlyDigits = (v) => String(v ?? "").replace(/\D/g, "");

const parseAmount = (v) => {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number") return v;

  const cleaned = String(v)
    .replace(/[$\s]/g, "")
    .replace(",", ".");

  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
};

const cleanBank = (str) =>
  normalize(str)
    .replace(/\b(banco|cuenta|corriente|ahorro|ahorros|cta|cc)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const splitWords = (str) =>
  normalize(str)
    .split(/\s+/)
    .filter((w) => w.length >= 2);

const tokenRatio = (a, b) => {
  const aw = [...new Set(splitWords(a))];
  const bw = [...new Set(splitWords(b))];

  if (!aw.length || !bw.length) return 0;

  let matches = 0;

  for (const w of bw) {
    const found = aw.some((o) => {
      if (o === w) return true;

      if (o.length >= 4 && w.length >= 4) {
        return o.includes(w.slice(0, 4)) || w.includes(o.slice(0, 4));
      }

      return false;
    });

    if (found) matches++;
  }

  return matches / bw.length;
};

const safeDateOnly = (f) => {
  if (!f) return null;

  const s = String(f).trim();
  let d;

  const m = s.match(/^(\d{4})-(\d{2})-(\d{2})/);

  if (m) {
    d = new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
  } else {
    d = new Date(s);
  }

  if (Number.isNaN(d.getTime())) return null;

  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
};

const webhookVal = (obj, paths, fallback = "") => {
  for (const path of paths) {
    const value = path.split(".").reduce((acc, key) => acc?.[key], obj);

    if (value !== undefined && value !== null && value !== "") {
      return value;
    }
  }

  return fallback;
};

// ==========================
// 🔹 4. DATOS OCR / IA
// ==========================
const comprobanteOCR = onlyDigits(parsed.comprobante) || null;
const montoOCR = parseAmount(parsed.monto);

const bancoOCR = normalize(parsed.banco);
const bancoOCRClean = cleanBank(parsed.banco);

const fechaOCR = parsed.fecha || null;

const beneficiarioOCR = normalize(parsed.beneficiario || parsed.titular || "");
const remitenteOCR = normalize(parsed.remitente || "");

const cuentaDestinoOCR = onlyDigits(
  parsed.cuenta_destino_ultimos4 ||
  parsed.cuenta_destino ||
  ""
);

const cuentaOrigenOCR = onlyDigits(
  parsed.cuenta_origen_ultimos4 ||
  parsed.cuenta_origen ||
  ""
);

// ==========================
// 🔹 5. DATOS WEBHOOK REAL
// ==========================
const webhook = $("afiliados").first().json.body;

const comprobanteWebhook = onlyDigits(
  webhookVal(webhook, ["payment_number", "numcomprobante"])
);

const montoWebhook = parseAmount(
  webhookVal(webhook, ["amount", "valor"])
);

const bancoWebhookRaw = webhookVal(webhook, [
  "bank.name",
  "banco.nombre",
  "banco_nombre"
]);

const bancoWebhook = normalize(bancoWebhookRaw);
const bancoWebhookClean = cleanBank(bancoWebhookRaw);

const titularWebhookRaw = webhookVal(webhook, [
  "bank.owner",
  "banco.propietario"
]);

const titularWebhook = normalize(titularWebhookRaw);

const cuentaWebhook = onlyDigits(
  webhookVal(webhook, ["bank.number", "banco.numero"])
);

const fechaWebhook = webhook.created_at;

// ==========================
// 🔹 6. VALIDACIONES
// ==========================
let erroresCriticos = [];
let advertencias = [];
let validaciones = {};

if (!jsonValido) {
  erroresCriticos.push("Respuesta IA no es JSON válido");
}

// ==========================
// ✔ COMPROBANTE
// ==========================
// OJO: este ya NO rechaza automáticamente si no coincide.
// Muchas veces el usuario escribe mal el número, pero la imagen sí es válida.
validaciones.comprobante = {
  ocr: comprobanteOCR,
  webhook: comprobanteWebhook,
  ok: Boolean(
    comprobanteOCR &&
    comprobanteWebhook &&
    comprobanteOCR === comprobanteWebhook
  )
};

if (!comprobanteOCR) {
  advertencias.push("Comprobante no detectado");
} else if (!validaciones.comprobante.ok) {
  advertencias.push("Comprobante no coincide con el número escrito por el usuario");
}

if (comprobanteOCR && /^(\d)\1+$/.test(comprobanteOCR)) {
  erroresCriticos.push("Comprobante sospechoso");
}

// ==========================
// ✔ MONTO
// ==========================
validaciones.monto = {
  ocr: montoOCR,
  webhook: montoWebhook,
  ok:
    montoOCR !== null &&
    montoWebhook !== null &&
    Math.abs(montoOCR - montoWebhook) <= 0.01
};

if (!validaciones.monto.ok) {
  erroresCriticos.push("Monto no coincide");
}

// ==========================
// ✔ BANCO
// ==========================
const bankRatio = Math.max(
  tokenRatio(bancoOCRClean, bancoWebhookClean),
  tokenRatio(bancoWebhookClean, bancoOCRClean)
);

const bancoOk = Boolean(
  bancoOCRClean &&
  bancoWebhookClean &&
  (
    bancoOCRClean.includes(bancoWebhookClean) ||
    bancoWebhookClean.includes(bancoOCRClean) ||
    bankRatio >= 0.5
  )
);

validaciones.banco = {
  ocr: bancoOCR,
  webhook: bancoWebhook,
  ocr_limpio: bancoOCRClean,
  webhook_limpio: bancoWebhookClean,
  ratio: Math.round(bankRatio * 100),
  ok: bancoOk
};

if (!bancoOk) {
  erroresCriticos.push("Banco no coincide");
}

// ==========================
// ✔ BENEFICIARIO / CUENTA DESTINO
// ==========================
const cuentaWebhookUltimos4 = cuentaWebhook.slice(-4);
const cuentaDestinoUltimos4 = cuentaDestinoOCR.slice(-4);

const cuentaOk = Boolean(
  cuentaDestinoUltimos4 &&
  cuentaWebhookUltimos4 &&
  cuentaWebhook.endsWith(cuentaDestinoUltimos4)
);

const beneficiarioRatio = Math.max(
  tokenRatio(beneficiarioOCR, titularWebhook),
  tokenRatio(titularWebhook, beneficiarioOCR)
);

const beneficiarioOk = Boolean(
  beneficiarioOCR &&
  (
    beneficiarioOCR.includes(titularWebhook) ||
    titularWebhook.includes(beneficiarioOCR) ||
    beneficiarioRatio >= 0.45 ||
    (beneficiarioOCR.includes("aet") && titularWebhook.includes("aet")) ||
    beneficiarioOCR.includes("esteban trader academy")
  )
);

validaciones.beneficiario = {
  beneficiario_ocr: beneficiarioOCR,
  remitente_ocr: remitenteOCR,
  titular_webhook: titularWebhook,
  cuenta_destino_ocr: cuentaDestinoUltimos4 || null,
  cuenta_webhook_ultimos4: cuentaWebhookUltimos4 || null,
  cuenta_ok: cuentaOk,
  beneficiario_ok: beneficiarioOk,
  ratio: Math.round(beneficiarioRatio * 100),
  ok: cuentaOk || beneficiarioOk
};

if (!validaciones.beneficiario.ok) {
  erroresCriticos.push("Beneficiario / cuenta destino no coincide");
}

// ==========================
// ✔ FECHA INTELIGENTE
// ==========================
const fOCR = safeDateOnly(fechaOCR);
const fWEB = safeDateOnly(fechaWebhook);

let diffDias = null;
let fechaOk = false;

if (fOCR && fWEB) {
  diffDias = Math.abs((fWEB - fOCR) / (1000 * 60 * 60 * 24));

  const isWeekend = (date) => {
    const day = date.getDay();
    return day === 0 || day === 6;
  };

  const maxDias = isWeekend(fOCR) || isWeekend(fWEB) ? 3 : 2;

  fechaOk = diffDias <= maxDias;

  if (!fechaOk) {
    erroresCriticos.push(`Fecha fuera de rango (${diffDias} días)`);
  }
} else {
  advertencias.push("Fecha no detectada o inválida");
}

validaciones.fecha = {
  ocr: fechaOCR,
  webhook: fechaWebhook,
  diff_dias: diffDias,
  ok: fechaOk
};

// ==========================
// 🚨 ANTIFRAUDE
// ==========================
if (parsed.legible === false) {
  erroresCriticos.push("Imagen no legible");
}

if (parsed.borroso === true) {
  erroresCriticos.push("Imagen borrosa");
}

if (parsed.editado === true) {
  erroresCriticos.push("Posible edición");
}

if (parsed.realista === false) {
  erroresCriticos.push("No parece real");
}

const confianza = Number(parsed.confianza ?? 0);

if (parsed.confianza !== undefined && confianza < 65) {
  erroresCriticos.push("Baja confianza IA");
} else if (parsed.confianza !== undefined && confianza < 75) {
  advertencias.push("Confianza IA media");
}

// ==========================
// 🧠 SCORE
// ==========================
let score = 100;

if (parsed.borroso) score -= 20;
if (parsed.editado) score -= 40;
if (parsed.realista === false) score -= 40;
if (parsed.legible === false) score -= 30;
if (parsed.confianza !== undefined && confianza < 75) score -= 10;

score = Math.max(0, score);

if (score < 60) {
  erroresCriticos.push("Score antifraude bajo");
}

// ==========================
// 🧾 RESULTADO FINAL
// ==========================
const aprobado = erroresCriticos.length === 0;

return [
  {
    json: {
      aprobado,

      decision: aprobado ? "aprobado" : "rechazado",

      errores: erroresCriticos.join(", "),
      advertencias: advertencias.join(", "),

      score,

      data_extraida: {
        comprobante: comprobanteOCR,
        comprobanteWebhook,

        monto: montoOCR,
        montoWebhook,

        banco: bancoOCR,
        bancoWebhook,

        fecha: fechaOCR,
        fechaWebhook,

        beneficiario: beneficiarioOCR,
        remitente: remitenteOCR,

        cuenta_destino_ultimos4: cuentaDestinoUltimos4 || null,
        cuenta_origen_ultimos4: cuentaOrigenOCR.slice(-4) || null,
        cuentaWebhookUltimos4: cuentaWebhookUltimos4 || null,

        titularWebhook
      },

      validaciones,

      payment_id: webhook.payment_id,
      approve_url: webhook.approve_url,
      reject_url: webhook.reject_url,

      raw
    }
  }
];

// rango en segundos
const min = 20;
const max = 90; // puedes subir a 120 o más

const delay = Math.floor(Math.random() * (max - min + 1)) + min;

return [
  {
    json: {
      ...$json,
      delay
    }
  }
];

const item = $json;

const phoneRaw = String(item.phone ?? "").trim();
const number = phoneRaw.replace(/\D/g, ""); // Evo API normalmente sin +

if (!number) {
return []; // omite items sin telefono valido
}

const firstName = String(item.name ?? "cliente")
.trim()
.split(/\s+/)[0];

const membershipType = String(item.membership?.type ?? "membresia");
const expiredDate = String(item.membership?.expired_date ?? "");
const reminderText = String(item.reminder?.message_es ?? "Tu membresia vencio hoy. Por favor reactiva.");

const text =
"Hola " + firstName + " 👋\n\n" +
reminderText + "\n" +
(expiredDate ? ("\nFecha de vencimiento: " + expiredDate) : "") +
"\nTipo: " + membershipType;

return [
  {
    json: {
      ...item,
      number,
      text,
      otro: "hola",
    }
  }
];
